code = """import json, re

def load_records(v):
    if isinstance(v, str) and v.endswith('.json'):
        with open(v, 'r', encoding='utf-8') as f:
            return json.load(f)
    return v

doc = load_records(var_call_93iUgNSWyeThhGTDEocK1tQs)[0]
lines = [ln.strip() for ln in doc['text'].splitlines()]

section_start_pat = re.compile(r'^\s*Disaster\s+(Recovery\s+)?Projects', re.IGNORECASE)
section_end_pat = re.compile(r'^\s*(Capital\s+Improvement\s+Projects|Staff\s+has\s+also\b)', re.IGNORECASE)
sched_start_pat = re.compile(r'^\s*(Project\s+Schedule|Estimated\s+Schedule)\b', re.IGNORECASE)
begin_pat = re.compile(r'\b(Begin\s+Construction|Construction\s+Start|Start\s+Construction|Award\s+Contract\s+and\s+Begin\s+Construction)\s*:\s*(.+)$', re.IGNORECASE)

projects = {}
in_disaster=False
current=None
in_schedule=False
for ln in lines:
    if not ln:
        continue
    if section_start_pat.match(ln):
        in_disaster=True
        current=None
        in_schedule=False
        continue
    if in_disaster and section_end_pat.match(ln):
        break
    if not in_disaster:
        continue
    if sched_start_pat.match(ln):
        in_schedule=True
        continue
    if not ln.startswith('(cid') and ':' not in ln and not re.match(r'^(Updates|Project\s+Description|Discussion|Recommended\s+Action|Page\s+\d+|Agenda\s+Item)', ln, re.IGNORECASE):
        if len(ln)<=140 and not re.match(r'^(Complete\s+Design|Advertise|Begin\s+Construction|Final\s+Design|Complete\s+Construction|Completion\s+Date)\b', ln, re.IGNORECASE):
            current=ln
            in_schedule=False
            projects.setdefault(current, {'st':None})
            continue
    if current:
        m=begin_pat.search(ln)
        if m and projects[current]['st'] is None:
            projects[current]['st']=m.group(2).strip()

out={'count':len(projects),'sample':list(projects.items())[:20]}
print('__RESULT__:')
print(json.dumps(out))"""

